def top_customers(path: str, limit: int = 3) -> list[str]:
    totals = {}
    with open(path) as f:
        for row in csv.DictReader(f):
            if row['status'] != 'paid':
                continue
            customer = row['customer']
            amount = int(row['amount'])
            totals[customer] = totals.get(customer, 0) + amount
    # Сортировка: сначала по сумме (убывание), затем по имени (возрастание)
    sorted_customers = sorted(totals.items(), key=lambda item: (-item[1], item[0]))
    return [name for name, _ in sorted_customers[:limit]]

